class Solution:
    def maxScoreIndices(self, nums: List[int]) -> List[int]:
        max_score = 0
        max_indices = []
        score = 0
        for i in range(len(nums)):
            if nums[i] == 0:
                score += 1
            else:
                score -= 1
            if score > max_score:
                max_score = score
                max_indices = [i]
            elif score == max_score:
                max_indices.append(i)
        return max_indices

